mapper.select:
SELECT COUNT(*)
FROM web_note_behavior b
INNER JOIN web_note n ON b.nid = n.id AND n.deleted = 0
WHERE n.uid = #{creatorUid}
  AND b.event_type = 'exposure'
  AND b.create_time >= #{startTime}
  AND b.create_time <= #{endTime}

SELECT COUNT(*)
FROM web_note_behavior b
INNER JOIN web_note n ON b.nid = n.id AND n.deleted = 0
WHERE n.uid = #{creatorUid}
  AND b.event_type = 'view'
  AND b.create_time >= #{startTime}
  AND b.create_time <= #{endTime}

SELECT IFNULL(b.scene, 'other') AS scene, COUNT(*) AS cnt
FROM web_note_behavior b
INNER JOIN web_note n ON b.nid = n.id AND n.deleted = 0
WHERE n.uid = #{creatorUid}
  AND b.event_type = 'view'
  AND b.create_time >= #{startTime}
  AND b.create_time <= #{endTime}
GROUP BY IFNULL(b.scene, 'other')

SELECT HOUR(b.create_time) AS hour, COUNT(*) AS cnt
FROM web_note_behavior b
INNER JOIN web_note n ON b.nid = n.id AND n.deleted = 0
WHERE n.uid = #{creatorUid}
  AND b.event_type = 'view'
  AND b.create_time >= #{startTime}
  AND b.create_time <= #{endTime}
GROUP BY HOUR(b.create_time)

SELECT
    IFNULL(SUM(b.duration_sec), 0) AS totalDurationSec,
    COUNT(*) AS watchCount,
    IFNULL(SUM(IFNULL(b.completed, 0)), 0) AS completedCount
FROM web_note_behavior b
INNER JOIN web_note n ON b.nid = n.id AND n.deleted = 0
WHERE n.uid = #{creatorUid}
  AND b.event_type = 'watch'
  AND b.create_time >= #{startTime}
  AND b.create_time <= #{endTime}

SELECT DATE_FORMAT(b.create_time, '%Y-%m-%d') AS date, COUNT(*) AS cnt
FROM web_note_behavior b
INNER JOIN web_note n ON b.nid = n.id AND n.deleted = 0
WHERE n.uid = #{creatorUid}
  AND b.event_type = 'view'
  AND b.create_time >= #{startTime}
  AND b.create_time <= #{endTime}
GROUP BY DATE_FORMAT(b.create_time, '%Y-%m-%d')

