SELECT b.nid AS nid, SUM(CASE WHEN b.event_type = 'exposure' THEN 1 ELSE 0 END) AS exposure, SUM(CASE WHEN b.event_type = 'view' THEN 1 ELSE 0 END) AS views, SUM(CASE WHEN b.event_type = 'share' THEN 1 ELSE 0 END) AS shares, SUM(CASE WHEN b.event_type = 'watch' THEN IFNULL(b.duration_sec, 0) ELSE 0 END) AS totalDurationSec, SUM(CASE WHEN b.event_type = 'watch' THEN 1 ELSE 0 END) AS watchCount, SUM(CASE WHEN b.event_type = 'watch' THEN IFNULL(b.completed, 0) ELSE 0 END) AS completedCount FROM web_note_behavior b WHERE b.nid IN
#{nid}
AND b.create_time >= #{startTime} AND b.create_time <= #{endTime} GROUP BY b.nid

